const svg = await page.$('svg.absolute');
const box = await svg.boundingBox();
const cx = box.x + box.width * 0.5;
const cy = box.y + box.height * 0.4;
const res = await page.evaluate(({ cx, cy }) => {
  const el = document.querySelector('svg.absolute');
  if (!el) return 'no svg';
  const ev = new PointerEvent('pointerdown', { bubbles: true, cancelable: true, clientX: cx, clientY: cy, pointerId: 1, pointerType: 'mouse' });
  el.dispatchEvent(ev);
  return 'dispatched';
}, { cx, cy });
await page.waitForTimeout(200);
const lineCount = await page.$$eval('svg.absolute line', (ls) => ls.length);
return JSON.stringify({ res, lineCount, box });
